html:
{% set co = get_company_info(doc.company) %}
{% set co_addr = get_company_address(doc.company) %}

<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body {
  font-family: 'Inter', Arial, sans-serif;
  font-size: 11px;
  color: #1a1a1a;
  background: white;
  padding: 8px;
}
.ol-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  padding-bottom: 18px;
  border-bottom: 3px solid #0F2340;
  margin-bottom: 22px;
}
.ol-company-name {
  font-size: 20px;
  font-weight: 800;
  color: #0F2340;
  letter-spacing: 1.5px;
  text-transform: uppercase;
}
.ol-company-meta {
  font-size: 9.5px;
  color: #555;
  margin-top: 6px;
  line-height: 1.7;
}
.ol-doc-block { text-align: right; min-width: 200px; }
.ol-doc-type {
  font-size: 16px;
  font-weight: 800;
  color: #16A34A;
  text-transform: uppercase;
  letter-spacing: 2px;
}
.ol-doc-number {
  font-size: 12px;
  font-weight: 700;
  color: #0F2340;
  margin-top: 5px;
}
.ol-doc-meta {
  font-size: 9.5px;
  color: #555;
  margin-top: 5px;
  line-height: 1.8;
}
.ol-doc-meta b { color: #0F2340; }
.ol-section-label {
  font-size: 8.5px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.2px;
  color: #16A34A;
  margin-bottom: 6px;
}
.ol-two-col {
  display: flex;
  gap: 24px;
  margin-bottom: 22px;
}
.ol-box {
  flex: 1;
  background: #f6f8fd;
  border-left: 3px solid #0F2340;
  padding: 10px 14px;
}
.ol-box-title {
  font-size: 8px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #16A34A;
  margin-bottom: 5px;
}
.ol-box-name {
  font-size: 12px;
  font-weight: 700;
  color: #0F2340;
}
.ol-box-meta {
  font-size: 9.5px;
  color: #555;
  margin-top: 3px;
  line-height: 1.6;
}
.ol-ref-bar {
  background: #f0fdf4;
  border: 1px solid #bbf7d0;
  border-radius: 4px;
  padding: 7px 12px;
  font-size: 9.5px;
  color: #555;
  margin-bottom: 18px;
  display: flex;
  gap: 24px;
}
.ol-ref-bar b { color: #0F2340; }
table.ol-items {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 16px;
  font-size: 10.5px;
}
table.ol-items thead tr { background: #0F2340; color: #fff; }
table.ol-items thead th {
  padding: 8px 10px;
  font-size: 9.5px;
  font-weight: 600;
  letter-spacing: 0.4px;
}
table.ol-items tbody tr { border-bottom: 1px solid #e4e8f0; }
table.ol-items tbody tr:nth-child(even) { background: #f6f8fd; }
table.ol-items tbody td { padding: 7px 10px; vertical-align: top; }
.ol-item-desc { font-size: 9px; color: #777; margin-top: 2px; }
.ol-totals-wrap { display: flex; justify-content: flex-end; margin-bottom: 24px; }
.ol-totals { width: 260px; }
.ol-totals table { width: 100%; border-collapse: collapse; }
.ol-totals td { padding: 5px 8px; font-size: 10.5px; }
.ol-totals .lbl { color: #555; }
.ol-totals .val { text-align: right; font-weight: 600; }
.ol-totals .sep { border-top: 1px solid #ddd; }
.ol-total-row { background: #0F2340; color: #fff; }
.ol-total-row td { padding: 8px 10px; font-size: 12px; font-weight: 700; }
.ol-total-row .val { text-align: right; }
.ol-terms {
  font-size: 9.5px;
  color: #555;
  border-top: 1px solid #ddd;
  padding-top: 12px;
  margin-bottom: 20px;
  line-height: 1.6;
}
.ol-terms b { color: #0F2340; }
.ol-footer {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  border-top: 1px solid #ddd;
  padding-top: 14px;
  font-size: 9px;
  color: #888;
}
.ol-sig-block { text-align: center; width: 180px; }
.ol-sig-line { border-bottom: 1px solid #aaa; height: 44px; margin-bottom: 5px; }
.tr { text-align: right; }
.tc { text-align: center; }
</style>

<!-- HEADER -->
<div class="ol-header">
  <div>
    <div class="ol-company-name">{{ doc.company }}</div>
    <div class="ol-company-meta">
      {%- if co_addr %}{{ co_addr }}<br>{% endif %}
      {%- if co.phone %}{{ _("Tél") }}: {{ co.phone }}<br>{% endif %}
      {%- if co.email %}{{ co.email }}<br>{% endif %}
      {%- if co.tax_id %}{{ _("ICE") }} : {{ co.tax_id }}{% endif %}
    </div>
  </div>
  <div class="ol-doc-block">
    <div class="ol-doc-type">{{ _("Bon de Commande") }}</div>
    <div class="ol-doc-number">{{ doc.name }}</div>
    <div class="ol-doc-meta">
      {{ _("Date") }} : <b>{{ frappe.format_date(doc.transaction_date) }}</b><br>
      {%- if doc.delivery_date %}
      {{ _("Livraison prévue") }} : <b>{{ frappe.format_date(doc.delivery_date) }}</b><br>
      {%- endif %}
      {%- if doc.po_no %}
      {{ _("Réf. client") }} : <b>{{ doc.po_no }}</b>
      {%- endif %}
    </div>
  </div>
</div>

<!-- CLIENT + DELIVERY -->
<div class="ol-two-col">
  <div class="ol-box">
    <div class="ol-box-title">{{ _("Donneur d'ordre") }}</div>
    <div class="ol-box-name">{{ doc.customer_name }}</div>
    {%- if doc.address_display %}
    <div class="ol-box-meta">{{ doc.address_display | striptags | replace('\n', ', ') }}</div>
    {%- endif %}
    {%- if doc.contact_display %}
    <div class="ol-box-meta">{{ _("Contact") }} : {{ doc.contact_display }}</div>
    {%- endif %}
  </div>
  {%- if doc.shipping_address %}
  <div class="ol-box">
    <div class="ol-box-title">{{ _("Adresse de livraison") }}</div>
    <div class="ol-box-meta">{{ doc.shipping_address | striptags | replace('\n', ', ') }}</div>
  </div>
  {%- endif %}
</div>

<!-- REF BAR -->
{%- if doc.items and doc.items[0].prevdoc_docname %}
<div class="ol-ref-bar">
  <span>{{ _("Devis de référence") }} : <b>{{ doc.items[0].prevdoc_docname }}</b></span>
  {%- if doc.payment_terms_template %}
  <span>{{ _("Conditions paiement") }} : <b>{{ doc.payment_terms_template }}</b></span>
  {%- endif %}
</div>
{%- endif %}

<!-- ITEMS -->
<div class="ol-section-label">{{ _("Articles commandés") }}</div>
<table class="ol-items">
  <thead>
    <tr>
      <th class="tc" style="width:28px">#</th>
      <th style="width:110px">{{ _("Référence") }}</th>
      <th>{{ _("Désignation") }}</th>
      <th class="tc" style="width:48px">{{ _("Qté") }}</th>
      <th class="tc" style="width:38px">{{ _("U.") }}</th>
      <th class="tc" style="width:90px">{{ _("Livraison") }}</th>
      <th class="tr" style="width:96px">{{ _("Prix Unit. HT") }}</th>
      <th class="tr" style="width:96px">{{ _("Montant HT") }}</th>
    </tr>
  </thead>
  <tbody>
    {%- for item in doc.items %}
    <tr>
      <td class="tc">{{ loop.index }}</td>
      <td>{{ item.item_code }}</td>
      <td>
        {{ item.item_name }}
        {%- if item.description and item.description != item.item_name %}
        <div class="ol-item-desc">{{ item.description | striptags }}</div>
        {%- endif %}
      </td>
      <td class="tc">{{ item.qty | int if item.qty == (item.qty | int) else item.qty }}</td>
      <td class="tc">{{ item.uom }}</td>
      <td class="tc" style="font-size:9px">
        {%- if item.delivery_date %}{{ frappe.format_date(item.delivery_date) }}{%- endif %}
      </td>
      <td class="tr">{{ format_currency_fr(item.rate, doc.currency) }}</td>
      <td class="tr">{{ format_currency_fr(item.amount, doc.currency) }}</td>
    </tr>
    {%- endfor %}
  </tbody>
</table>

<!-- TOTALS -->
<div class="ol-totals-wrap">
  <div class="ol-totals">
    <table>
      <tr>
        <td class="lbl">{{ _("Sous-total HT") }}</td>
        <td class="val">{{ format_currency_fr(doc.total, doc.currency) }}</td>
      </tr>
      {%- for tax in doc.taxes %}
      <tr>
        <td class="lbl">{{ tax.description }}</td>
        <td class="val">{{ format_currency_fr(tax.tax_amount, doc.currency) }}</td>
      </tr>
      {%- endfor %}
      {%- if doc.discount_amount %}
      <tr>
        <td class="lbl">{{ _("Remise") }}</td>
        <td class="val">- {{ format_currency_fr(doc.discount_amount, doc.currency) }}</td>
      </tr>
      {%- endif %}
      <tr class="sep"><td colspan="2"></td></tr>
      <tr class="ol-total-row">
        <td>{{ _("TOTAL TTC") }}</td>
        <td class="val">{{ format_currency_fr(doc.grand_total, doc.currency) }}</td>
      </tr>
    </table>
  </div>
</div>

<!-- TERMS -->
{%- if doc.terms %}
<div class="ol-terms"><b>{{ _("Conditions") }} :</b> {{ doc.terms }}</div>
{%- endif %}

<!-- FOOTER -->
<div class="ol-footer">
  <div>
    <b>{{ doc.company }}</b>
    {%- if co_addr %}<br>{{ co_addr }}{% endif %}
    {%- if co.phone %}<br>{{ co.phone }}{% endif %}
  </div>
  <div class="ol-sig-block">
    <div class="ol-sig-line"></div>
    <div>{{ _("Signature &amp; Cachet Client") }}</div>
    <div style="margin-top:5px;font-size:8px">{{ _("Bon pour accord") }}</div>
  </div>
</div>
